/*
 * Ribbon add-in commands (ExecuteFunction handlers).
 *
 * These run WITHOUT the task pane open — one-click ribbon actions. Each handler
 * is a thin wrapper that calls the shared core/office logic and then signals
 * completion; no business logic lives here.
 *
 * PowerPoint ExecuteFunction commands can't show pane UI, so failures/guards are
 * silent (logged to the console) — the action just no-ops when preconditions
 * aren't met (e.g. fewer than 2 shapes).
 */

/* global Office, console, localStorage */

import { SizeMode, sizeToReference } from "../core";
import { applyShapes, insertSpikeTestShapes, readSelectedShapes } from "../office";

/** Ribbon command: drop the A–D test shapes for the selection-order spike. */
async function insertTestShapes(event: Office.AddinCommands.Event): Promise<void> {
  try {
    await insertSpikeTestShapes();
  } catch (error) {
    console.error("insertTestShapes failed:", error);
  } finally {
    event.completed();
  }
}

/**
 * Master for ribbon match-size. The task pane writes the tracked reference id to
 * localStorage (same origin, shared with this commands runtime); if that shape
 * is in the current selection we use it, otherwise we fall back to the last
 * shape in the returned order. (A ribbon command can't show the pane's picker.)
 */
function resolveMasterId(ids: string[]): string {
  let stored = "";
  try {
    stored = localStorage.getItem("shapeTools.referenceId") || "";
  } catch {
    stored = "";
  }
  return ids.indexOf(stored) >= 0 ? stored : ids[ids.length - 1];
}

/** M10 ribbon: apply the master shape's width / height / both to the others. */
async function matchSize(mode: SizeMode, event: Office.AddinCommands.Event): Promise<void> {
  try {
    const shapes = await readSelectedShapes();
    if (shapes.length >= 2) {
      const masterId = resolveMasterId(shapes.map((s) => s.id));
      const master = shapes.find((s) => s.id === masterId) || shapes[shapes.length - 1];
      await applyShapes(sizeToReference(shapes, mode, master));
    }
  } catch (error) {
    console.error("matchSize failed:", error);
  } finally {
    event.completed();
  }
}

// Register ribbon commands. FunctionName in the manifest must match these ids.
Office.onReady(() => {
  Office.actions.associate("insertTestShapes", insertTestShapes);
  Office.actions.associate("matchWidth", (event: Office.AddinCommands.Event) =>
    matchSize("width", event)
  );
  Office.actions.associate("matchHeight", (event: Office.AddinCommands.Event) =>
    matchSize("height", event)
  );
  Office.actions.associate("matchBoth", (event: Office.AddinCommands.Event) =>
    matchSize("both", event)
  );
});
