/*
 * M10 — Copy to (office adapter).
 *
 * Office.js has no native duplicate, so we copy by RECONSTRUCTION: read the
 * source's geometry/rotation/fill/line/text/font and build a fresh shape with
 * the matching .add* method. This is faithful for text boxes; for geometric
 * shapes we can't read the silhouette (the API has no readable geometricShape
 * type), so the copy is a rectangle carrying all other properties — reported
 * back as an "outline approximated" caveat.
 *
 * Anything we can't reconstruct (pictures, groups, tables, charts, SmartArt, or
 * shapes with gradient/pattern/picture fills) FALLS BACK to inserting a flattened
 * PNG of the source (getImageAsBase64 → setSelectedDataAsync), reported as a
 * "flattened image" caveat so the user is never handed a silently broken copy.
 *
 * The created copies are selected at the end so repeated presses chain in the
 * same direction.
 */

/* global PowerPoint, Office, OfficeExtension */

import { copyPlacement, CopyDirection } from "../core";

/** Types we can rebuild as editable shapes. */
const RECONSTRUCTABLE = new Set(["TextBox", "GeometricShape"]);
/** Fills we can faithfully reproduce; anything else forces the image fallback. */
const REPRODUCIBLE_FILLS = new Set(["Solid", "NoFill"]);

export interface CopyResult {
  /** Copies rebuilt as editable shapes. */
  reconstructed: number;
  /** Geometric shapes whose outline couldn't be preserved (copied as rectangle). */
  outlineApprox: string[];
  /** Sources copied as a flattened (non-editable) image. */
  flattened: string[];
  /** Ids of all created copies (used to reselect for chaining). */
  newIds: string[];
}

interface FlattenJob {
  base64: string;
  left: number;
  top: number;
  width: number;
  height: number;
  label: string;
}

export async function copyShapesTo(direction: CopyDirection, gap: number): Promise<CopyResult> {
  const result: CopyResult = { reconstructed: 0, outlineApprox: [], flattened: [], newIds: [] };
  const flattenJobs: FlattenJob[] = [];

  // Phase 1: read sources, reconstruct what we can, capture PNGs for the rest.
  await PowerPoint.run(async (context) => {
    const slide = context.presentation.getSelectedSlides().getItemAt(0);
    const selected = context.presentation.getSelectedShapes();
    selected.load(
      "items/id,items/name,items/type,items/left,items/top,items/width,items/height,items/rotation"
    );
    await context.sync();

    const sources = selected.items.slice();

    // Load rich props only on reconstructable-typed shapes (others would throw).
    for (const s of sources) {
      if (RECONSTRUCTABLE.has(s.type as unknown as string)) {
        s.fill.load("type,foregroundColor,transparency");
        s.lineFormat.load("color,weight,dashStyle,style,visible");
        s.textFrame.load("hasText");
        s.textFrame.textRange.load("text");
        s.textFrame.textRange.font.load("name,size,bold,italic,color,underline");
      }
    }
    await context.sync();

    const created: PowerPoint.Shape[] = [];
    const pngJobs: Array<{
      result: OfficeExtension.ClientResult<string>;
      job: Omit<FlattenJob, "base64">;
    }> = [];

    for (const s of sources) {
      const type = s.type as unknown as string;
      const label = s.name || s.id;
      const place = copyPlacement(
        { left: s.left, top: s.top, width: s.width, height: s.height },
        direction,
        gap
      );
      const opts = { left: place.left, top: place.top, width: s.width, height: s.height };

      const reconstructable =
        RECONSTRUCTABLE.has(type) && REPRODUCIBLE_FILLS.has(s.fill.type as unknown as string);
      if (reconstructable) {
        const copy = buildReconstructedCopy(slide, s, type, opts, result, label);
        copy.load("id");
        created.push(copy);
        result.reconstructed++;
      } else {
        pngJobs.push({
          result: s.getImageAsBase64(),
          job: { left: place.left, top: place.top, width: s.width, height: s.height, label },
        });
      }
    }
    await context.sync();

    for (const c of created) {
      result.newIds.push(c.id);
    }
    for (const p of pngJobs) {
      flattenJobs.push({ ...p.job, base64: p.result.value });
    }
  });

  // Phase 2: insert each flattened PNG (Common API), then position it. This is
  // inherently sequential — each insert hijacks the selection, so we must place
  // (and record) one image before inserting the next.
  for (const job of flattenJobs) {
    await insertImageAtSelection(job.base64);
    /* eslint-disable office-addins/no-context-sync-in-loop */
    await PowerPoint.run(async (context) => {
      const sel = context.presentation.getSelectedShapes();
      sel.load("items/id");
      await context.sync();
      const img = sel.items[sel.items.length - 1];
      if (img) {
        img.left = job.left;
        img.top = job.top;
        img.width = job.width;
        img.height = job.height;
        img.load("id");
        await context.sync();
        result.newIds.push(img.id);
      }
    });
    /* eslint-enable office-addins/no-context-sync-in-loop */
    result.flattened.push(job.label);
  }

  // Phase 3: select the copies so repeated presses chain in the same direction.
  if (result.newIds.length > 0) {
    await PowerPoint.run(async (context) => {
      const slide = context.presentation.getSelectedSlides().getItemAt(0);
      slide.setSelectedShapes(result.newIds);
      await context.sync();
    });
  }

  return result;
}

function buildReconstructedCopy(
  slide: PowerPoint.Slide,
  source: PowerPoint.Shape,
  type: string,
  opts: PowerPoint.ShapeAddOptions,
  result: CopyResult,
  label: string
): PowerPoint.Shape {
  const hasText = source.textFrame.hasText;
  const text = hasText ? source.textFrame.textRange.text : "";

  let copy: PowerPoint.Shape;
  if (type === "TextBox") {
    copy = slide.shapes.addTextBox(text, opts);
  } else {
    // Geometric: outline isn't readable, so we rebuild as a rectangle.
    copy = slide.shapes.addGeometricShape(PowerPoint.GeometricShapeType.rectangle, opts);
    if (hasText) {
      copy.textFrame.textRange.text = text;
    }
    result.outlineApprox.push(label);
  }

  if (typeof source.rotation === "number") {
    copy.rotation = source.rotation;
  }

  // Fill.
  const fillType = source.fill.type as unknown as string;
  if (fillType === "NoFill") {
    copy.fill.clear();
  } else if (fillType === "Solid") {
    copy.fill.setSolidColor(source.fill.foregroundColor);
    if (typeof source.fill.transparency === "number") {
      copy.fill.transparency = source.fill.transparency;
    }
  }

  // Line.
  if (source.lineFormat.visible) {
    copy.lineFormat.visible = true;
    if (source.lineFormat.color) {
      copy.lineFormat.color = source.lineFormat.color;
    }
    if (typeof source.lineFormat.weight === "number") {
      copy.lineFormat.weight = source.lineFormat.weight;
    }
    copy.lineFormat.dashStyle = source.lineFormat.dashStyle;
    copy.lineFormat.style = source.lineFormat.style;
  } else {
    copy.lineFormat.visible = false;
  }

  // Font (range-level; per-run detail on mixed text isn't preserved).
  if (hasText) {
    const src = source.textFrame.textRange.font;
    const dst = copy.textFrame.textRange.font;
    if (src.name) {
      dst.name = src.name;
    }
    if (typeof src.size === "number") {
      dst.size = src.size;
    }
    if (src.bold !== null) {
      dst.bold = src.bold;
    }
    if (src.italic !== null) {
      dst.italic = src.italic;
    }
    if (src.color) {
      dst.color = src.color;
    }
    if (src.underline) {
      dst.underline = src.underline;
    }
  }

  return copy;
}

/** Inserts a base64 PNG onto the active slide via the Common API; it lands selected. */
function insertImageAtSelection(base64: string): Promise<void> {
  return new Promise((resolve, reject) => {
    Office.context.document.setSelectedDataAsync(
      base64,
      { coercionType: Office.CoercionType.Image },
      (res) => {
        if (res.status === Office.AsyncResultStatus.Succeeded) {
          resolve();
        } else {
          reject(new Error(res.error ? res.error.message : "Could not insert image copy."));
        }
      }
    );
  });
}
