/*
 * M13 — Paste element onto multiple selected slides.
 *
 * SPIKE RESULT (confirmed against the type defs):
 *   - Office.js has no shape clone / clipboard / ShapeRange; ShapeCollection is
 *     add-only (addGeometricShape / addTextBox / addLine / addTable / addGroup).
 *   - There is NO addImage/addPicture in PowerPoint's ShapeCollection, so a
 *     picture cannot be inserted onto an arbitrary slide. Pictures are refused.
 *   - A geometric shape's silhouette isn't readable, so it reconstructs as a
 *     rectangle (reported as a caveat).
 *
 * Flow is copy → paste, because selecting slides in the thumbnail pane deselects
 * the shape: `captureElement` reads the source once; `pasteToSelectedSlides`
 * reconstructs it on every selected slide. Round-trippable properties: geometry,
 * rotation, solid/no fill, line (color/weight/dash/style/visible), text, and
 * range-level font.
 */

/* global PowerPoint */

const RECONSTRUCTABLE = new Set(["GeometricShape", "TextBox"]);
const REPRODUCIBLE_FILLS = new Set(["Solid", "NoFill"]);

export interface CapturedElement {
  kind: "geometric" | "textbox";
  left: number;
  top: number;
  width: number;
  height: number;
  rotation: number;
  text: string;
  fillType?: string;
  fillColor?: string;
  fillTransparency?: number;
  lineVisible?: boolean;
  lineColor?: string;
  lineWeight?: number;
  lineDash?: string;
  lineStyle?: string;
  fontName?: string | null;
  fontSize?: number | null;
  fontBold?: boolean | null;
  fontItalic?: boolean | null;
  fontUnderline?: string | null;
  fontColor?: string | null;
}

export interface CaptureResult {
  element?: CapturedElement;
  /** Human summary of what was captured (the spike readout). */
  summary?: string;
  problem?: string;
}

export async function captureElement(referenceId: string | null): Promise<CaptureResult> {
  if (!referenceId) {
    return { problem: "Select the shape to copy first." };
  }
  return PowerPoint.run(async (context) => {
    const selected = context.presentation.getSelectedShapes();
    selected.load(
      "items/id,items/type,items/left,items/top,items/width,items/height,items/rotation"
    );
    await context.sync();

    const source =
      selected.items.find((s) => s.id === referenceId) || selected.items[selected.items.length - 1];
    if (!source) {
      return { problem: "Select the shape to copy first." };
    }
    const type = source.type as unknown as string;
    if (!RECONSTRUCTABLE.has(type)) {
      return {
        problem: `Can't paste a ${type} to other slides — Office.js can only rebuild geometric shapes and text boxes (no picture/chart/group/table insert across slides).`,
      };
    }

    source.fill.load("type,foregroundColor,transparency");
    source.lineFormat.load("visible,color,weight,dashStyle,style");
    source.textFrame.load("hasText");
    source.textFrame.textRange.load("text");
    source.textFrame.textRange.font.load("name,size,bold,italic,underline,color");
    await context.sync();

    const fillType = source.fill.type as unknown as string;
    if (!REPRODUCIBLE_FILLS.has(fillType)) {
      return {
        problem:
          "That shape's fill (gradient/pattern/picture) can't be rebuilt. Use a solid or no fill.",
      };
    }

    const el: CapturedElement = {
      kind: type === "TextBox" ? "textbox" : "geometric",
      left: source.left,
      top: source.top,
      width: source.width,
      height: source.height,
      rotation: source.rotation,
      text: source.textFrame.hasText ? source.textFrame.textRange.text : "",
      fillType,
      fillColor: fillType === "Solid" ? source.fill.foregroundColor : undefined,
      fillTransparency: fillType === "Solid" ? source.fill.transparency : undefined,
      lineVisible: source.lineFormat.visible,
      lineColor: source.lineFormat.color,
      lineWeight: source.lineFormat.weight,
      lineDash: source.lineFormat.dashStyle as unknown as string,
      lineStyle: source.lineFormat.style as unknown as string,
      fontName: source.textFrame.textRange.font.name,
      fontSize: source.textFrame.textRange.font.size,
      fontBold: source.textFrame.textRange.font.bold,
      fontItalic: source.textFrame.textRange.font.italic,
      fontUnderline: source.textFrame.textRange.font.underline as unknown as string | null,
      fontColor: source.textFrame.textRange.font.color,
    };

    const facets = ["geometry", "fill", "line"];
    if (el.text) {
      facets.push("text+font");
    }
    const outline = el.kind === "geometric" ? " (outline → rectangle)" : "";
    return { element: el, summary: `Copied ${el.kind}: ${facets.join(", ")}${outline}.` };
  });
}

export interface PasteResult {
  slides: number;
  problem?: string;
}

export async function pasteToSelectedSlides(el: CapturedElement): Promise<PasteResult> {
  return PowerPoint.run(async (context) => {
    const slides = context.presentation.getSelectedSlides();
    slides.load("items/id");
    await context.sync();

    if (slides.items.length === 0) {
      return { slides: 0, problem: "Select one or more slides in the thumbnail pane first." };
    }
    for (const slide of slides.items) {
      reconstructOnSlide(slide, el);
    }
    await context.sync();
    return { slides: slides.items.length };
  });
}

function reconstructOnSlide(slide: PowerPoint.Slide, el: CapturedElement): void {
  const opts = { left: el.left, top: el.top, width: el.width, height: el.height };
  let shape: PowerPoint.Shape;
  if (el.kind === "textbox") {
    shape = slide.shapes.addTextBox(el.text, opts);
  } else {
    shape = slide.shapes.addGeometricShape(PowerPoint.GeometricShapeType.rectangle, opts);
    if (el.text) {
      shape.textFrame.textRange.text = el.text;
    }
  }

  if (typeof el.rotation === "number") {
    shape.rotation = el.rotation;
  }

  if (el.fillType === "NoFill") {
    shape.fill.clear();
  } else if (el.fillType === "Solid" && el.fillColor) {
    shape.fill.setSolidColor(el.fillColor);
    if (typeof el.fillTransparency === "number") {
      shape.fill.transparency = el.fillTransparency;
    }
  }

  if (el.lineVisible !== undefined) {
    shape.lineFormat.visible = el.lineVisible;
    if (el.lineVisible) {
      if (el.lineColor) {
        shape.lineFormat.color = el.lineColor;
      }
      if (typeof el.lineWeight === "number") {
        shape.lineFormat.weight = el.lineWeight;
      }
      if (el.lineDash) {
        shape.lineFormat.dashStyle = el.lineDash as unknown as PowerPoint.ShapeLineDashStyle;
      }
      if (el.lineStyle) {
        shape.lineFormat.style = el.lineStyle as unknown as PowerPoint.ShapeLineStyle;
      }
    }
  }

  if (el.text) {
    const f = shape.textFrame.textRange.font;
    if (el.fontName) {
      f.name = el.fontName;
    }
    if (typeof el.fontSize === "number") {
      f.size = el.fontSize;
    }
    if (el.fontBold !== null && el.fontBold !== undefined) {
      f.bold = el.fontBold;
    }
    if (el.fontItalic !== null && el.fontItalic !== undefined) {
      f.italic = el.fontItalic;
    }
    if (el.fontUnderline) {
      f.underline = el.fontUnderline as unknown as PowerPoint.ShapeFontUnderlineStyle;
    }
    if (el.fontColor) {
      f.color = el.fontColor;
    }
  }
}
