/*
 * Central capability / feature-detection helpers.
 *
 * The spec requires feature-detecting EVERY API with isSetSupported and
 * degrading gracefully. Rather than sprinkle version strings across the
 * codebase, every requirement the add-in depends on is named here once, so we
 * have a single place to bump versions and a single vocabulary for the UI to
 * explain "this action needs a newer PowerPoint".
 */

/* global Office */

export type Platform = "PC" | "Mac" | "OfficeOnline" | "iOS" | "Android" | "Universal" | "Unknown";

/**
 * Named PowerPoint requirement sets this add-in relies on, with the minimum
 * version each feature needs. Keep the human-readable `why` — the UI surfaces
 * it when a capability is missing.
 */
export const REQUIREMENTS = {
  /** getSelectedShapes / setSelectedShapes, shape geometry read/write. */
  selectedShapes: {
    set: "PowerPointApi",
    version: "1.5",
    why: "read and change the selected shapes",
  },
  /** presentation.pageSetup.slideWidth/Height (used by align/fit to slide). */
  pageSetup: { set: "PowerPointApi", version: "1.10", why: "align and fit relative to the slide" },
  /** shape.getTextFrameOrNullObject() — safe text access on any shape type. */
  textFrameNull: {
    set: "PowerPointApi",
    version: "1.10",
    why: "scale font size safely on any shape",
  },
  /** shape tags (used by M8 Hide/Unhide). */
  tags: { set: "PowerPointApi", version: "1.3", why: "store hidden-shape state in tags" },
  /** table row height / column width (used by Decompose for a proportional layout). */
  tableGeom: {
    set: "PowerPointApi",
    version: "1.9",
    why: "use real column/row sizes when decomposing",
  },
} as const;

export type RequirementKey = keyof typeof REQUIREMENTS;

export function isSupported(key: RequirementKey): boolean {
  const req = REQUIREMENTS[key];
  try {
    return Office.context.requirements.isSetSupported(req.set, req.version);
  } catch {
    return false;
  }
}

/** Best-effort host platform. Used to warn where APIs (e.g. M9) are unreliable. */
export function platform(): Platform {
  try {
    const p = Office.context.platform;
    switch (p) {
      case Office.PlatformType.PC:
        return "PC";
      case Office.PlatformType.Mac:
        return "Mac";
      case Office.PlatformType.OfficeOnline:
        return "OfficeOnline";
      case Office.PlatformType.iOS:
        return "iOS";
      case Office.PlatformType.Android:
        return "Android";
      case Office.PlatformType.Universal:
        return "Universal";
      default:
        return "Unknown";
    }
  } catch {
    return "Unknown";
  }
}

export function isWeb(): boolean {
  return platform() === "OfficeOnline";
}
