/*
 * M9 — Select similar.
 *
 * From the reference shape, select every shape on the slide that matches the
 * chosen criteria (type / fill color / line color / line style / width / height,
 * each toggleable), via Slide.setSelectedShapes.
 *
 * Desktop-first: on PowerPoint on the web, changing the selection programmatically
 * is unreliable, so we still attempt it but flag `isWeb` for the UI to warn.
 */

/* global PowerPoint */

import { isWeb } from "./capabilities";

/** Shape types with a comparable fill. */
const FILL_TYPE_LIST = ["GeometricShape", "TextBox", "Placeholder", "Callout", "Freeform"];
const FILL_TYPES = new Set(FILL_TYPE_LIST);
/** Shape types with a comparable line format (fill-capable ones plus lines). */
const LINE_TYPES = new Set([...FILL_TYPE_LIST, "Line"]);
/** Size match tolerance in points (guards float noise). */
const SIZE_TOLERANCE = 0.5;

export interface SimilarCriteria {
  type: boolean;
  fill: boolean;
  lineColor: boolean;
  lineStyle: boolean;
  height: boolean;
  width: boolean;
}

export interface SimilarResult {
  /** Number of shapes selected (includes the reference). */
  count: number;
  /** False if the reference shape couldn't be found on the slide. */
  refFound: boolean;
  /** True on PowerPoint web, where setSelectedShapes is unreliable. */
  isWeb: boolean;
}

interface FillInfo {
  type: string;
  color: string;
}

interface LineInfo {
  visible: boolean;
  color: string;
  dashStyle: string;
}

export async function selectSimilar(
  referenceId: string | null,
  criteria: SimilarCriteria
): Promise<SimilarResult> {
  const web = isWeb();
  if (!referenceId) {
    return { count: 0, refFound: false, isWeb: web };
  }
  const needFill = criteria.fill;
  const needLine = criteria.lineColor || criteria.lineStyle;

  return PowerPoint.run(async (context) => {
    const slide = context.presentation.getSelectedSlides().getItemAt(0);
    /* eslint-disable office-addins/load-object-before-read, office-addins/call-sync-before-read --
       .shapes is a navigation property; it's loaded below before its items are read. */
    const shapeColl = slide.shapes;
    shapeColl.load("items/id,items/type,items/width,items/height");
    await context.sync();

    const shapes = shapeColl.items;
    /* eslint-enable office-addins/load-object-before-read, office-addins/call-sync-before-read */

    const ref = shapes.find((s) => s.id === referenceId);
    if (!ref) {
      return { count: 0, refFound: false, isWeb: web };
    }

    const fills = new Map<string, FillInfo>();
    const lines = new Map<string, LineInfo>();
    if (needFill || needLine) {
      for (const s of shapes) {
        const type = s.type as unknown as string;
        if (needFill && FILL_TYPES.has(type)) {
          s.fill.load("type,foregroundColor");
        }
        if (needLine && LINE_TYPES.has(type)) {
          s.lineFormat.load("visible,color,dashStyle");
        }
      }
      await context.sync();
      for (const s of shapes) {
        const type = s.type as unknown as string;
        if (needFill && FILL_TYPES.has(type)) {
          fills.set(s.id, {
            type: s.fill.type as unknown as string,
            color: s.fill.foregroundColor,
          });
        }
        if (needLine && LINE_TYPES.has(type)) {
          lines.set(s.id, {
            visible: s.lineFormat.visible,
            color: s.lineFormat.color,
            dashStyle: s.lineFormat.dashStyle as unknown as string,
          });
        }
      }
    }

    // A criterion only applies if the reference itself exposes that property.
    const refFill = fills.get(ref.id);
    const refLine = lines.get(ref.id);
    const compareFill = criteria.fill && !!refFill;
    const compareLineColor = criteria.lineColor && !!refLine;
    const compareLineStyle = criteria.lineStyle && !!refLine;

    const matchIds: string[] = [];
    for (const s of shapes) {
      if (criteria.type && (s.type as unknown as string) !== (ref.type as unknown as string)) {
        continue;
      }
      if (criteria.width && Math.abs(s.width - ref.width) >= SIZE_TOLERANCE) {
        continue;
      }
      if (criteria.height && Math.abs(s.height - ref.height) >= SIZE_TOLERANCE) {
        continue;
      }
      if (compareFill) {
        const f = fills.get(s.id);
        if (
          !f ||
          f.type !== refFill.type ||
          (refFill.type === "Solid" && f.color !== refFill.color)
        ) {
          continue;
        }
      }
      if (compareLineColor) {
        const l = lines.get(s.id);
        // Same visibility, and (when visible) same color.
        if (!l || l.visible !== refLine.visible || (refLine.visible && l.color !== refLine.color)) {
          continue;
        }
      }
      if (compareLineStyle) {
        const l = lines.get(s.id);
        if (!l || l.dashStyle !== refLine.dashStyle) {
          continue;
        }
      }
      matchIds.push(s.id);
    }

    slide.setSelectedShapes(matchIds);
    await context.sync();

    return { count: matchIds.length, refFound: true, isWeb: web };
  });
}
